class DefaultPaymentGateway(
    private val context: Context
) : PaymentGateway {

    override fun process(request: PaymentRequest): PaymentResult {
        return when (request.source) {
            is PaymentSource.InAppPurchase -> {
                PaymentResult(
                    transactionId = request.transactionId,
                    success = true,
                    message = "In-app purchase processed",
                    providerReference = "iap_${request.source.productId}_${request.transactionId}"
                )
            }
            is PaymentSource.Wallet -> {
                PaymentResult(
                    transactionId = request.transactionId,
                    success = true,
                    message = "Wallet transaction processed",
                    providerReference = "wallet_${request.source.walletId}_${request.transactionId}"
                )
            }
        }
    }

    override fun refund(transactionId: String, amountCents: Long?): PaymentResult {
        return PaymentResult(
            transactionId = transactionId,
            success = true,
            message = "Refund processed",
            providerReference = "refund_$transactionId"
        )
    }
}

